const llm = $json;
const runCfg = $('Set — Run config').first().json;
const digestInput = $('Code — build digest input').first().json;
let digest;
try {
  const text = llm?.content?.[0]?.text;
  if (!text) throw new Error('no_content_in_anthropic_response');
  digest = JSON.parse(text);
} catch (e) {
  digest = { week_of: runCfg.week_of, headline_stats: { competitors_monitored: 5, high_signal_count: 0, medium_signal_count: 0, low_signal_count: 5, scrape_failures: digestInput.competitors_with_failed_scrapes.length }, high_priority: [], medium_priority: [], low_priority: { competitor_names: digestInput.competitors_monitored, note: 'Digest synthesis failed — raw signals available in Supabase. See Notion run log.' }, data_quality_warnings: [`⚠️ Digest synthesis error: ${e.message}`], recommended_actions: ['RevOps: review Langfuse trace for this run and re-run synthesis manually.'] };
}
const slug = (s) => String(s || '').toLowerCase().replace(/[^a-z0-9]+/g,'-').replace(/(^-|-$)/g,'');
const confidenceEmoji = (c) => c >= 80 ? '✅' : c >= 50 ? '⚠️' : '🟥';
const overallConfidence = (() => {
  const cs = (digestInput.signals_this_week || []).map(s => s.confidence).filter(c => typeof c === 'number');
  if (!cs.length) return 0;
  return Math.round(cs.reduce((a,b)=>a+b,0)/cs.length);
})();
const blocks = [];
blocks.push({ type: 'header', text: { type: 'plain_text', text: `🔍 Weekly Competitive Intel — week of ${digest.week_of}`, emoji: true } });
blocks.push({ type: 'context', elements: [ { type: 'mrkdwn', text: `*${digest.headline_stats.competitors_monitored}* competitors monitored  ·  *${digest.headline_stats.high_signal_count}* HIGH  ·  *${digest.headline_stats.medium_signal_count}* MEDIUM  ·  *${digest.headline_stats.low_signal_count}* LOW` }, { type: 'mrkdwn', text: `_Generated ${runCfg.generated_at} CET  ·  Run ID \`${runCfg.run_id}\`_` } ] });
blocks.push({ type: 'divider' });
for (const comp of (digest.high_priority || [])) {
  const compSlug = slug(comp.competitor_name);
  const deltaBadge = comp.delta === 'NEW' ? '`NEW this week`' : '`ongoing from last week`';
  const bullets = (comp.bullets || []).map(b => `• ${b}`).join('\n');
  blocks.push({ type: 'section', text: { type: 'mrkdwn', text: `*🔴 HIGH — ${comp.competitor_name}*  ${deltaBadge}\n${bullets}` } });
  blocks.push({ type: 'actions', block_id: `actions_${compSlug}`, elements: [ { type: 'button', text: { type: 'plain_text', text: 'View full report' }, value: `view::${compSlug}::${runCfg.run_id}`, action_id: 'view_full_report' }, { type: 'button', text: { type: 'plain_text', text: 'Mark as read' }, value: `ack::${compSlug}::${runCfg.run_id}`, action_id: 'mark_as_read' }, { type: 'button', style: 'danger', text: { type: 'plain_text', text: 'Flag' }, value: `flag::${compSlug}::${runCfg.run_id}`, action_id: 'flag_signal' } ] });
  blocks.push({ type: 'divider' });
}
for (const comp of (digest.medium_priority || [])) {
  const compSlug = slug(comp.competitor_name);
  const deltaBadge = comp.delta === 'NEW' ? '`NEW this week`' : '`ongoing from last week`';
  const bullets = (comp.bullets || []).map(b => `• ${b}`).join('\n');
  blocks.push({ type: 'section', text: { type: 'mrkdwn', text: `*🟡 MEDIUM — ${comp.competitor_name}*  ${deltaBadge}\n${bullets}` } });
  blocks.push({ type: 'divider' });
}
if (digest.low_priority && (digest.low_priority.competitor_names || []).length) {
  const names = digest.low_priority.competitor_names.join(', ');
  const note = digest.low_priority.note || 'No significant signals this week.';
  blocks.push({ type: 'section', text: { type: 'mrkdwn', text: `*🟢 LOW — ${names}*\n_${note}_` } });
  blocks.push({ type: 'divider' });
}
if ((digest.data_quality_warnings || []).length) {
  const warns = digest.data_quality_warnings.map(w => `• ${w}`).join('\n');
  blocks.push({ type: 'section', text: { type: 'mrkdwn', text: `:warning: *Data quality warnings*\n${warns}` } });
  blocks.push({ type: 'divider' });
}
if ((digest.recommended_actions || []).length) {
  const actions = digest.recommended_actions.map(a => `• ${a}`).join('\n');
  blocks.push({ type: 'section', text: { type: 'mrkdwn', text: `*🎯 Recommended actions*\n${actions}` } });
  blocks.push({ type: 'divider' });
}
blocks.push({ type: 'context', elements: [ { type: 'mrkdwn', text: '💬 Ask anytime: `/intel <competitor> <timeframe>`  —  e.g. `/intel Pigment last 30 days`' }, { type: 'mrkdwn', text: `Data confidence overall: *${overallConfidence}%* ${confidenceEmoji(overallConfidence)}  ·  Run \`${runCfg.run_id}\`` } ] });
return [{ json: { digest, overall_confidence: overallConfidence, slack_payload: { text: `🔍 Weekly Competitive Intel — week of ${digest.week_of}`, blocks } } }];

